  Log logger = LogFactory.getLog("Ascension-Rule-Persona-Management-RuleLibrary");
	String KEY_CUSTOM_OBJ_NAME = "Ascension-Custom-Constants";
	String logName = "rule.Ascension-Rule-Persona-Management-RuleLibrary";
	
	/***************************************************************************************************
    * This method is to get Current Date in the format yyyy-MM-dd'T'HH:mm:ss.SSS
    * Input: void
    * Output : date
    ***************************************************************************************************/

  public String getCurrentDateIncludingMilliSeconds(){
    
    debug(logName, "Entering method getCurrentDateIncludingMilliSeconds");

    SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS");
    String formattedDate = sdf.format(new Date());
    
    debug(logName, "Exiting method getCurrentDateIncludingMilliSeconds");
    
    return formattedDate;

  }


  /***************************************************************************************************
    * This method is to generate random password using AD Default Password Policy
    * Input: void
    * Output : password
    ***************************************************************************************************/

  public String getRandomPasswordUsingADPasswordPolicy(){

    debug(logName, "Entering method getRandomPasswordUsingADPasswordPolicy");

    String passwordAD = null;

    PasswordPolicy policy = context.getObjectByName(PasswordPolicy.class, "AD Default Password Policy"); 

    try{

      passwordAD = new PasswordGenerator(context).generatePassword(policy);

    }

    catch (RuntimeException e) {

      error(logName, "Exception occurred while generating password" + e);

    }

    debug(logName, "Exiting method getRandomPasswordUsingADPasswordPolicy");

    return passwordAD;
  }

  /***************************************************************************************************
    * This method is to get the password and clear it from Custom Object
    * Input: identity
    * Output : password
    ***************************************************************************************************/

  public String getPasswordFromCustom(Identity identity){

    debug(logName, "Entering method getPasswordFromCustom");

    String passwordAD = null;

    if(null == identity){

      debug(logName, "Exiting method getPasswordFromCustom - Identity Object is Null");

      return passwordAD;

    }

    String currentDate = getCurrentDateIncludingMilliSeconds();

    String internalID = identity.getAttribute("internalId");

    debug(logName, currentDate + " - " + "Internal ID for the identity - " + identity.getName() + " is: " + internalID);

    Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-AMITA-Joiner");

    //context.decache(custom);

    if(null != custom && !Util.isEmpty(internalID)){

      try{

        Map map = custom.get("AMITA password");

        if(!Util.isEmpty(map) && !Util.isEmpty(map.get(internalID))){

          passwordAD = context.decrypt(map.get(internalID));

          if(Util.isEmpty(passwordAD)){

            debug(logName, currentDate + " - Retrieved password from Custom for the identity - " + identity.getName());

          }

          map.remove(internalID);

          custom.put("AMITA password", map);

          context.saveObject(custom);
          context.commitTransaction();

          debug(logName, currentDate + " - Removed password from Custom for the identity - " + identity.getName());

        }
      } catch(Exception e){

        error(logName, "Error in retrieving password for PRESENCEHEALTH account: " + e);

      }
    }

    if(Util.isEmpty(passwordAD)){

      debug(logName, currentDate + " - Generating Random password for the PRSENCEHEALTH account of the identity - " + identity.getName());

      passwordAD = getRandomPasswordUsingADPasswordPolicy();

      //add exception to the custom object

      if(null != custom){

        try{

          Map exceptions = custom.get("Exceptions");

          if(null == exceptions){
            exceptions = new HashMap();
          }

          exceptions.put(internalID, "AD-AMITA password not found in the custom object for user: " + identity.getName());

          custom.put("Exceptions", exceptions);

          context.saveObject(custom);
          context.commitTransaction();

        } catch(Exception e){

          error(logName, "Error in setting exceptions in custom: " + e);

        }

      }
    }

    debug(logName, "Exiting method getPasswordFromCustom");

    return passwordAD;
  }



  /***************************************************************************************************
    * This method is to store password in Custom Object
    * Input: identity, password
    * Output : null
    ***************************************************************************************************/

  public void storePasswordInCustom(Identity identity, String passwordAD){

    debug(logName, "Entering method storePasswordInCustom");

    if(null != identity){

      String currentDate = getCurrentDateIncludingMilliSeconds();

      String internalID = identity.getAttribute("internalId");

      try{

        Custom customPwd = context.getObjectByName(Custom.class, "Ascension-Custom-AMITA-Joiner");

        if(null != customPwd){

          Map map = customPwd.get("AMITA password");

          if(map == null){
            map = new HashMap();
          }

          debug(logName, currentDate + " - Storing password in Custom for the identity - " + identity.getName());

          map.put(internalID, context.encrypt(passwordAD));

          customPwd.put("AMITA password", map);

          context.saveObject(customPwd);
          context.commitTransaction();

        }
      } catch(Exception e){

        error(logName, "Error in storing password in custom: " + e);

      }
    }

    debug(logName, "Exiting method storePasswordInCustom");
  }

	
	  /***************************************************************************************************
	* This method formats the date format from MM/dd to MMM/dd
	* Method returns the formated date
	* Input: dob
	* Output : outputDate - String
	***************************************************************************************************/
  
   public String dateFormatMmToMmm(String dob){
    String outputDate = "";
    SimpleDateFormat inputFormat = new SimpleDateFormat("MM/dd");
    SimpleDateFormat outputFormat = new SimpleDateFormat("MMM/dd", Locale.ENGLISH);
    Date date = inputFormat.parse(dob);
    outputDate = outputFormat.format(date);	
    return outputDate;
	 }  
 
	
  /***************************************************************************************************
	* This method performs correlation based on Internal ID and persona type
	* Method returns the matched identity name
	* Input: baseSID
	* Output : returnMap - Map
	***************************************************************************************************/
	public Map findInternalIdBasedCorrelationMap(String baseSID)
	{
        constantCustom = context.getObjectByName(Custom.class, KEY_CUSTOM_OBJ_NAME);
		if (constantCustom == null)
		{
			throw new RuntimeException("No custom object can be found! name: " + KEY_CUSTOM_OBJ_NAME);
		}
		String KEY_INTERNAL_ID_SEPARATOR = constantCustom.getString("KEY_INTERNAL_ID_SEPARATOR");
		String KEY_INTERNAL_ID_ATTR_NAME = constantCustom.getString("KEY_INTERNAL_ID_ATTR_NAME");
		Map returnMap = new HashMap();
		try
		{
			Identity identity = context.getUniqueObject(Identity.class, Filter.and(Filter.like(KEY_INTERNAL_ID_ATTR_NAME, baseSID + KEY_INTERNAL_ID_SEPARATOR, MatchMode.START),Filter.ignoreCase(Filter.eq("personaType", "Primary"))));
			if(identity != null)
			{
				String identityName = identity.getName();
				logger.debug("Found Identity with Unique InternalId :"+ identityName);
				returnMap.put("identityName", identityName);
			}
		}
		catch(Exception e)
		{
			logger.error(e);
		} 
		return returnMap;
	}
  
  
  /***************************************************************************************************
	* This method fetches the next available Sailpoint Internal Identifier a call to a DB sequence 
	* Method returns the next Sailpoint Internal Identifier internalid
	* Output : internalid - string
	***************************************************************************************************/
  public String generateNextSailpointInternalIdentifier()
  {
    logger.debug("Entering method generateNextSailpointInternalIdentifier");
    String globalIdentifier = null;
    Connection conn = null;
    Statement stmt = null;
    ResultSet rs = null;
    try
    {
      conn = context.getJdbcConnection();
      stmt = conn.createStatement();
      String sql = "SELECT (NEXT VALUE FOR SailpointIdentifier) AS SID";
      rs = stmt.executeQuery(sql);
      if(null!=rs)
      {
        while(rs.next())
        {
          String globalId  = rs.getString("SID");
          if(null!=globalId)
          {
            Long gLong = Long.parseLong(globalId);
            Long gLongModified = gLong + 1;
            globalIdentifier = String.valueOf(gLongModified);
          }
        }
      }
    }
    catch(SQLException se)
    {
      logger.error(se);
	  throw new SQLException("Exception in internalid generation "+se.getMessage());
    }
    catch(Exception e)
    {
      logger.error(e); 
	  throw new Exception("Exception in internalid generation "+e.getMessage());
    }
    finally
    {
      //finally block used to close resources
      try
      {
        if(stmt!=null)
        {
          stmt.close();
        }
        if(rs!=null)
        {
          rs.close();
        }
      }
      catch(SQLException se)
      {
        logger.error(se);
      }
    }
    logger.debug("Exiting method generateNextSailpointInternalIdentifier");
    return globalIdentifier;
  }
  
  /***************************************************************************************************
	* This method decides if a new internal id should be created or the old internal id should be updated
	* Method returns the internalid for a parent identity
	* Input: oldInternalId, userName
	* Output : internalid - string
	***************************************************************************************************/
	
  public String createOrUpdateParentInternalID(String oldInternalId, String userName) 
  {
    logger.debug("Entering method createOrUpdateParentInternalID");
    constantCustom = context.getObjectByName(Custom.class, KEY_CUSTOM_OBJ_NAME);
    if (constantCustom == null)
	{
      throw new RuntimeException("No custom object can be found! name: " + KEY_CUSTOM_OBJ_NAME);
	}
    String KEY_INTERNAL_ID_SEPARATOR = constantCustom.getString("KEY_INTERNAL_ID_SEPARATOR");
	String newInternalId = "";
	if(oldInternalId.contains(KEY_INTERNAL_ID_SEPARATOR)) 
    {
	  newInternalId = generateNewInternalId();
	} 
    else 
    {
	  boolean checkIfUnique = isUnique(oldInternalId, userName);
      logger.debug("Parent Persona SID for " + userName + " is Unique: " + checkIfUnique);
	  if(!checkIfUnique) 
	  {
	    newInternalId = generateNewInternalId();
	  }
	  else
	  {
	    newInternalId = oldInternalId + "-1";
	  }
	}
    logger.debug("Exiting method createOrUpdateParentInternalID");
	return newInternalId;
  }
  
   /*************************************************************************************************************************************
	* This method decides if the given internalid is unique based on which a new internal id is created or the old internal id is updated
	* Method returns true or false
	* Input: oldInternalId, userName
	* Output : isIDUnique - boolean
	*************************************************************************************************************************************/
	
  public boolean isUnique(String oldInternalId, String userName) 
  {
    logger.debug("Entering method isUnique");
	QueryOptions qo = new QueryOptions();
    boolean isIDUnique = false;
    try
    {
      List identityObjectsList = context.getObjects(Identity.class, qo.addFilter(Filter.like("internalId", oldInternalId, MatchMode.START)));
      int userCount = identityObjectsList.size();
      if(userCount == 0)
	  {
	    isIDUnique = true;
	  }
	  else if(userCount == 1)
	  {
        Identity identity = identityObjectsList.get(0);
        if(Util.nullSafeCaseInsensitiveEq(userName, identity.getName()))
		{ 
		  isIDUnique = true;
		}
	  }  
    }
    catch (GeneralException e)
    {
      logger.error(e);
    }
	logger.debug("Exiting method isUnique");
	return isIDUnique;
  }
   /***************************************************************************************************
	* This method updates the child internalid and the childPersonas of the parent identity
	* Method returns the new internal id of the child identity
	* Input: userName, parentPersonaName, parentPersonaSID, oldInternalId
	* Output : InternalId - String
	***************************************************************************************************/
	
  public String updateChildInternalID(String userName, String parentPersonaName, String parentPersonaSID, String oldInternalId)
  {
    logger.debug("Entering method updateChildInternalID");
	Identity identity = context.getObjectByName(Identity.class, userName);
	String newInternalId = generateSPInternalId(userName, parentPersonaSID);
    logger.debug("updated child internal id: " + newInternalId);
    identity.setAttribute("internalId", newInternalId);
    context.saveObject(identity);
    context.commitTransaction();
    Identity parentIdentity = context.getObjectByName(Identity.class, parentPersonaName);
    if (parentIdentity == null) 
    {
       logger.error("parentIdentity not found: " + parentPersonaName);
    }
    else 
    {
       List childPersonas = parentIdentity.getAttribute("childPersonas");
       logger.debug("childPersonas: " + childPersonas);
       if (childPersonas != null && !childPersonas.isEmpty() && childPersonas.contains(oldInternalId)) 
       {
        childPersonas.remove(oldInternalId);
        childPersonas.add(newInternalId);
        parentIdentity.setAttribute("childPersonas", childPersonas);
        context.saveObject(parentIdentity);
        context.commitTransaction();
       }
    }
    logger.debug("Exiting method updateChildInternalID");
	return newInternalId;
  }
  
  
   /***************************************************************************************************
	* This method fetches the next available Sailpoint Internal Identifier for the new identity
	* Method returns the next Sailpoint Internal Identifier internalid for a parent identity
	* Output : internalid - string
	***************************************************************************************************/
	public String generateNewInternalId()
	{
	  logger.debug("Entering method generateNewInternalId");
      constantCustom = context.getObjectByName(Custom.class, KEY_CUSTOM_OBJ_NAME);
      if (constantCustom == null)
	  {
    	  throw new RuntimeException("No custom object can be found! name: " + KEY_CUSTOM_OBJ_NAME);
	  }
      String KEY_INTERNAL_ID_SEPARATOR = constantCustom.getString("KEY_INTERNAL_ID_SEPARATOR");
      String KEY_INTERNAL_ID_PRIMARY_SEQUENCE = constantCustom.getString("KEY_INTERNAL_ID_PRIMARY_SEQUENCE");
	  String KEY_LOOP_COUNT = constantCustom.getString("KEY_LOOP_COUNT");
      String baseInternalId = generateNextSailpointInternalIdentifier();
      QueryOptions qo = new QueryOptions();
      int userCount;
	  int loopCount = 0;
      try
      {
         userCount = context.countObjects(Identity.class, qo.addFilter(Filter.like("internalId", baseInternalId + KEY_INTERNAL_ID_SEPARATOR, MatchMode.START)));
         while (userCount > 0)
         {
            if(loopCount>=KEY_LOOP_COUNT)
            {
              logger.error("Could not generate SailPointInternalID. Reached highest number of iteration.");
              return "";
            }
            loopCount++;
            generateNewInternalId();
         }
      }
      catch (GeneralException e)
      {
         logger.error(e);
      }
	  logger.debug("Exiting method generateNewInternalId");
      return baseInternalId + KEY_INTERNAL_ID_SEPARATOR + KEY_INTERNAL_ID_PRIMARY_SEQUENCE;
    }
	
	/***************************************************************************************************
	* This method determines the child sequence number for given internal id
	* Method returns the sequence number as Int
	* Input: internalId
	* Output : internalSequence
	***************************************************************************************************/
	
	public int determineChildSquence(String internalId)
    {
	  logger.debug("Entering method determineChildSquence");
      constantCustom = context.getObjectByName(Custom.class, KEY_CUSTOM_OBJ_NAME);
      if (constantCustom == null)
	  {
    	  throw new RuntimeException("No custom object can be found! name: " + KEY_CUSTOM_OBJ_NAME);
	  }
      String KEY_INTERNAL_ID_SEPARATOR = constantCustom.getString("KEY_INTERNAL_ID_SEPARATOR");
      int internalSequence = 0;
      try
      {
      	internalSequence = Integer.parseInt(internalId.substring(internalId.indexOf(KEY_INTERNAL_ID_SEPARATOR) + 1, internalId.length()));
      }
      catch (Exception e)
      {
    	logger.error(e.getMessage());
      }
	  logger.debug("Exiting method determineChildSquence");
      return internalSequence;
    } 
	
    /***************************************************************************************************
	* This method determines the base id for the given sailpoint internal id
	* Method returns the base id
	* Input: primarySID
	* Output : base id - String
	***************************************************************************************************/
	
  public String determineBaseSID(String primarySID)
  {
	  logger.debug("Entering method determineBaseSID");
    
    constantCustom = context.getObjectByName(Custom.class, KEY_CUSTOM_OBJ_NAME);
    if (constantCustom == null)
	{
    	throw new RuntimeException("No custom object can be found! name: " + KEY_CUSTOM_OBJ_NAME);
	}
    String KEY_INTERNAL_ID_SEPARATOR = constantCustom.getString("KEY_INTERNAL_ID_SEPARATOR");
    if(Util.isNotNullOrEmpty(primarySID) && primarySID.contains(KEY_INTERNAL_ID_SEPARATOR))
    {
	    logger.debug("Exiting method determineBaseSID");
      return primarySID.substring(0, primarySID.indexOf(KEY_INTERNAL_ID_SEPARATOR));
    }
    else
    {
      logger.error("Method: determineBaseSID || primarySID is null or has incorrect format: " + primarySID);
    }
    return "";
  }
	
   /***************************************************************************************************
	* This method generates SailPoint InternalID for a child identity 
	* This is a method to be called only when baseSID value and personaType of an user is available
	* Input : personaType, baseSID
	* Output : next internalId for an existing users
	***************************************************************************************************/
	public String generateChildSPInternalID(String personaType, String baseSID)
    {
	  logger.debug("Entering method generateChildSPInternalID");
      constantCustom = context.getObjectByName(Custom.class, KEY_CUSTOM_OBJ_NAME);
      if (constantCustom == null)
	  {
    	throw new RuntimeException("No custom object can be found! name: " + KEY_CUSTOM_OBJ_NAME);
	  }
      String KEY_INTERNAL_ID_SEPARATOR = constantCustom.getString("KEY_INTERNAL_ID_SEPARATOR");
      String KEY_INTERNAL_ID_ATTR_NAME = constantCustom.getString("KEY_INTERNAL_ID_ATTR_NAME");
      String spInternalId = null;

      QueryOptions query = new QueryOptions();
      query.addFilter(Filter.like(KEY_INTERNAL_ID_ATTR_NAME, baseSID + KEY_INTERNAL_ID_SEPARATOR, MatchMode.START));
      List attrNames = new ArrayList();
      attrNames.add(KEY_INTERNAL_ID_ATTR_NAME);
      int highestChildSequence = 0;
      try
      {
        Iterator result = context.search(Identity.class, query, attrNames);
        int childSequence = 0;
          while (result.hasNext())
          {
            String internalId = (String) ((Object[]) result.next())[0];
            if (!internalId.contains(KEY_INTERNAL_ID_SEPARATOR))
			{
			  continue;
			}
            childSequence = determineChildSquence(internalId);
            if (childSequence > highestChildSequence)
			{
			  highestChildSequence = childSequence;
			}
          }
      }
      catch (GeneralException e)
      {
        logger.error(e.getDetailedError());
      }
	  logger.debug("Exiting method generateChildSPInternalID");
      return baseSID + KEY_INTERNAL_ID_SEPARATOR + ++highestChildSequence;
    }

   /***************************************************************************************************
	* This method generates SailPoint InternalID for a new identity of an existing user
	* Identity can be both Parent as well as a Child, but can not be of a new user
	* Input : identityName
	* Output : next internalId for an existing users
	***************************************************************************************************/
	
  public String generateSPInternalId(String identityName)
  {
	  logger.debug("Entering method generateSPInternalId");
    String spInternalId = null;
    if(Util.isNotNullOrEmpty(identityName)) 
    {
      try
      {
        Identity identity = context.getObjectByName(Identity.class, identityName);
        if (identity != null) 
        {
          String personaType = identity.getStringAttribute("personaType");
          String primarySID = identity.getStringAttribute("parentPersonaSID");
          if(Util.isNotNullOrEmpty(personaType) && Util.isNotNullOrEmpty(primarySID)) 
          {
            String baseSID = determineBaseSID(primarySID);
            spInternalId = generateChildSPInternalID(personaType, baseSID);
          } 
          else 
          {
            logger.error("Persona Type or parentPersonaSID cannot be found for " + identityName);
          }
        } 
        else 
        {
          logger.error("No identity can be found! identityName: " + identityName);
        }
      }
      catch (GeneralException e)
      {
        logger.error(e.getDetailedError());
      }
    }
    else 
    {
      logger.error("Empty identityName - " + identityName);
    }
	  logger.debug("Exiting method generateSPInternalId");
    return spInternalId;
  }
  
  /***************************************************************************************************
	* This method generates SailPoint InternalID for a new identity of an existing user
	* Identity can be both Parent as well as a Child, but can not be of a new user
	* Input : identityName, parentSID
	* Output : next internalId for an existing users
	***************************************************************************************************/
	
	public String generateSPInternalId(String identityName, String parentSID)
    {
	  logger.debug("Entering method generateSPInternalId");
      String spInternalId = null;
      if (Util.isNotNullOrEmpty(identityName) && Util.isNotNullOrEmpty(parentSID))
      {
        try
        {
          String baseSID = determineBaseSID(parentSID);
          spInternalId = generateChildSPInternalID("Child", baseSID);
        }
        catch (GeneralException e)
        {
          logger.error(e.getDetailedError());
        }
      } 
      else
      {
        logger.error("Identity name or parentSID is empty");
      }
	  logger.debug("Exiting method generateSPInternalId");
      return spInternalId;
	}

  /***************************************************************************************************
	* This method updates the child identities with the parent identity information
  * Go to each of the child / secondary identity using the childPersonas list and update the Parent Persona to the SID of primary persona
  * Input : childPersonaList - list of child sailpoint internal ids. SIDs
  * Input : parentIdName - name of the parent identity
	* Output : Update the child identities with the parent information.
  * Returns : nothing
	***************************************************************************************************/
  public void updateParentPersonaAttributesInSecondaryIdentities(List childPersonaList, String parentIdName)
  {
    logger.debug("Entering method updateParentPersonaAttributesInSecondaryIdentities");
    Identity parentIdentity = context.getObjectByName(Identity.class, parentIdName);
    String parentSID = parentIdentity.getAttribute("internalId");
    parentIdentity.removeAttribute("parentPersonaSID");
    parentIdentity.removeAttribute("parentPersonaName");
    try
    {
      Iterator identityIterator = null;
      if(null != childPersonaList)
      {
        for(String sid: childPersonaList)
        {
          QueryOptions queryOptions = new QueryOptions();
          queryOptions.addFilter(Filter.and(Filter.eq("internalId", sid)));
          identityIterator = context.search(Identity.class, queryOptions);
          if(null != identityIterator && identityIterator.hasNext())
          {
            Identity retrievedIdentity = (Identity)identityIterator.next();
            retrievedIdentity.setAttribute("parentPersonaSID", parentSID);
            retrievedIdentity.setAttribute("parentPersonaName", parentIdName);
            context.saveObject(retrievedIdentity);
            context.commitTransaction();
            //context.decache(retrievedIdentity);
          }
        }
      }
      if(null != identityIterator)
      {
        Util.flushIterator(identityIterator);
      }
    }
    catch(Exception e)
    {
      logger.error("An error occurred. Details:\n"+e.getMessage());
    }
    finally
    {
      context.saveObject(parentIdentity);
      context.commitTransaction();
      //context.decache(parentIdentity);
    }
    logger.debug("Exiting method updateParentPersonaAttributesInSecondaryIdentities");
  }

  /***************************************************************************************************
	* This method moves the AD, ServiceNow and GSuite links from source identity to target identity
  * Input : source - The source Identity name
  * Input : target - The target Identity name
	* Output : Moves the AD, ServiceNow and GSuite links from Source to Target identity
  * Returns : nothing
	***************************************************************************************************/
  public void moveIdentityLinks(String source, String target)
  {
    logger.debug("Entering method moveIdentityLinks");
    Identity sourceIdentity = context.getObjectByName(Identity.class,source);
    Identity targetIdentity = context.getObjectByName(Identity.class,target);

    List srclinks=sourceIdentity.getLinks();
    boolean gsuiteAcc = false;
    boolean adAmitaAcc = false;
	String amitaSamName = "";
    ProvisioningPlan plan = new ProvisioningPlan();  
    plan.setIdentity(targetIdentity); 
    plan.addRequester(context.getObjectByName(Identity.class, "IDM Team"));  
    plan.setSource(sailpoint.object.Source.Rule);    

    List appList = new ArrayList();
    appList.add("Active Directory - Direct");
    appList.add("G Suite");
    appList.add("ServiceNow");   
    for(Link linkToMove : srclinks)
    {
      if(null!=linkToMove && appList.contains(linkToMove.getApplication().getType()))
      {
        ProvisioningPlan.AccountRequest account = new ProvisioningPlan.AccountRequest();  
        account.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);  
        account.setApplication(ProvisioningPlan.APP_IIQ);
        ProvisioningPlan.AttributeRequest req = new ProvisioningPlan.AttributeRequest();  
        req.setName(ProvisioningPlan.ATT_IIQ_LINKS);  
        req.setOperation(ProvisioningPlan.Operation.Add);  
        req.put(ProvisioningPlan.ARG_SOURCE_IDENTITY, linkToMove.getIdentity().getName());  
        req.setValue(linkToMove.getId()); 
        account.add(req);  
        if(Util.nullSafeCaseInsensitiveEq(linkToMove.getApplication().getType(),"G Suite")){
          gsuiteAcc = true;
        }
       
        plan.add(account);  
      }
    }

    ProvisioningPlan.AccountRequest iiqAccount = new ProvisioningPlan.AccountRequest();  
    iiqAccount.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);  
    iiqAccount.setApplication(ProvisioningPlan.APP_IIQ);
	
	if(null != targetIdentity && Util.isNotNullOrEmpty(targetIdentity.getAttribute("initialOperId")) && Util.nullSafeCaseInsensitiveEq(targetIdentity.getStringAttribute("domain"),"AMITA")){
      if(Util.isNotNullOrEmpty(sourceIdentity.getStringAttribute("initialOperId"))){
        iiqAccount.add(new AttributeRequest("initialOperId", ProvisioningPlan.Operation.Set, sourceIdentity.getStringAttribute("initialOperId")));
      }else if(Util.isNotNullOrEmpty(amitaSamName)){
        iiqAccount.add(new AttributeRequest("initialOperId", ProvisioningPlan.Operation.Set, amitaSamName));
      }
    }

    //Updating Gsuite related attributes to the parent or target identity
    iiqAccount.add(new AttributeRequest("email", ProvisioningPlan.Operation.Set, sourceIdentity.getStringAttribute("email")));

    if(gsuiteAcc){
      iiqAccount.add(new AttributeRequest("orgUnitPath", ProvisioningPlan.Operation.Set, sourceIdentity.getStringAttribute("orgUnitPath")));
      iiqAccount.add(new AttributeRequest("gsuiteStatus", ProvisioningPlan.Operation.Set, sourceIdentity.getStringAttribute("gsuiteStatus")));
    }

    plan.add(iiqAccount);




    Provisioner provisioner = new Provisioner(context);  
    provisioner.setAssigner("IDM Team");   
    try
    {
      provisioner.setNoLocking(true);
      provisioner.setOptimisticProvisioning(true);
      provisioner.execute(plan);

      //Removing Gsuite related attributes from source identity
      sourceIdentity.setAttribute("email","");
      sourceIdentity.setAttribute("orgUnitPath","");
      sourceIdentity.setAttribute("gsuiteStatus","");
      context.startTransaction();
      context.saveObject(sourceIdentity);
      context.commitTransaction();

    }
    catch(GeneralException e)
    {
      logger.error("Exception occurred in compiling plan to move links ::"+e.getMessage());
    }
    finally
    {
      if(null!=sourceIdentity)
      {
        //context.decache(sourceIdentity);
      }

      if(null!=targetIdentity)
      {
        //context.decache(targetIdentity);
      }
    }
    logger.debug("Exiting method moveIdentityLinks");
  }
  
   public void updateLink(String target)
  {
    logger.debug("Entering method updateLink for identity :"+target);

    Identity targetIdentity = context.getObjectByName(Identity.class,target);

    List srclinks=targetIdentity.getLinks();
 

    ProvisioningPlan plan = new ProvisioningPlan();  
    plan.setIdentity(targetIdentity);
    plan.addRequester(context.getObjectByName(Identity.class, "IDM Team"));  
    plan.setSource(sailpoint.object.Source.Rule);    

    List appList = new ArrayList();
    appList.add("Active Directory - Direct");
  
    for(Link link : srclinks)
    {
      if(null!=link && appList.contains(link.getApplication().getType()))
      {
        ProvisioningPlan.AccountRequest account = new ProvisioningPlan.AccountRequest();  
        account.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);  

        if(Util.nullSafeCaseInsensitiveEq(link.getApplication().getName(),"AD-AMITA")){
          
					ProvisioningPlan.AccountRequest adAccountReq = new ProvisioningPlan.AccountRequest();
          adAccountReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);  
          adAccountReq.setApplication("AD-AMITA");
     

          List groups = new ArrayList();
          List removeGroups = new ArrayList();

          groups.add("CN=sec.O365_DUO_MFA_Enforce_Dynamic,OU=DUO,OU=Security,OU=AMITAGroups,DC=amita,DC=amitahealth,DC=org");
          groups.add("CN=sec.DUO_Lic_MFA_Dynamic,OU=DUO,OU=Security,OU=AMITAGroups,DC=amita,DC=amitahealth,DC=org");
          groups.add("CN=sec.O365Lic.F3,OU=O365,OU=Security,OU=AMITAGroups,DC=amita,DC=amitahealth,DC=org");

          if(null != targetIdentity && Util.nullSafeCaseInsensitiveEq(targetIdentity.getAttribute("type"),"employee")){
            

            if(null != link.getAttribute("memberOf")){
              if(link.getAttribute("memberOf") instanceof List){
                List existingGroups = link.getAttribute("memberOf");
                groups.removeAll(existingGroups);
              }else if(link.getAttribute("memberOf") instanceof String){
                String existingGroup = link.getAttribute("memberOf");
                groups.remove(existingGroup);
              }
            }
						
           
						if(!Util.isEmpty(groups)){
							for(String eachGroup : groups){
									logger.debug("Adding Attribute request for group  :"+eachGroup);
									adAccountReq.add(new AttributeRequest("memberof", ProvisioningPlan.Operation.Add, eachGroup));
								}
						}
           
           
            adAccountReq.add(new AttributeRequest("extensionAttribute9", ProvisioningPlan.Operation.Add, "EMP"));
			adAccountReq.add(new AttributeRequest("company", ProvisioningPlan.Operation.Add, ""));
            adAccountReq.add(new AttributeRequest("extensionAttribute4", ProvisioningPlan.Operation.Add, ""));
           
     
            plan.add(adAccountReq);
          }
		  
          else  if(null != targetIdentity && Util.nullSafeCaseInsensitiveEq(targetIdentity.getAttribute("type"),"non-hr contractor")){
						logger.debug("targetIdentity - non-hr contractor");
            if(null != link.getAttribute("memberOf")){
              if(link.getAttribute("memberOf") instanceof List && !Util.isEmpty(link.getAttribute("memberOf"))){
                List existingGroups = link.getAttribute("memberOf");
                for(String existingGroup : existingGroups){
                  if(groups.contains(existingGroup)){
                    removeGroups.add(existingGroup);        
                  }
                }
              }            
              else if(link.getAttribute("memberOf") instanceof String){
                if(link.getAttribute("memberOf").contains(groups)){
                  removeGroups.add(link.getAttribute("memberOf"));
                }
              }
            }
					  if(!Util.isEmpty(removeGroups)){
            	for(String eachGroup : removeGroups){
               
             	 adAccountReq.add(new AttributeRequest("memberOf", ProvisioningPlan.Operation.Remove, eachGroup));
   
								}
						}
				
            adAccountReq.add(new AttributeRequest("extensionAttribute9", ProvisioningPlan.Operation.Add, "CWR"));
            plan.add(adAccountReq);
          }
		  
          
		  	else  if(null != targetIdentity && Util.nullSafeCaseInsensitiveEq(targetIdentity.getAttribute("type"),"Physician")){         

            adAccountReq.add(new AttributeRequest("extensionAttribute9", ProvisioningPlan.Operation.Add, "89"));
			adAccountReq.add(new AttributeRequest("company", ProvisioningPlan.Operation.Add, ""));
            adAccountReq.add(new AttributeRequest("extensionAttribute4", ProvisioningPlan.Operation.Add, ""));
          
       
            plan.add(adAccountReq);
          }
        }
        
        else if(Util.nullSafeCaseInsensitiveEq(link.getApplication().getName(),"AD-PRESENCEHEALTH")) 
        {
          ProvisioningPlan.AccountRequest adAccountReq = new ProvisioningPlan.AccountRequest();
          adAccountReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);  
          adAccountReq.setApplication("AD-PRESENCEHEALTH");
          
          if(null != targetIdentity && (Util.nullSafeCaseInsensitiveEq(targetIdentity.getAttribute("type"),"Physician") || Util.nullSafeCaseInsensitiveEq(targetIdentity.getAttribute("type"),"employee")))
          {

            adAccountReq.add(new AttributeRequest("company", ProvisioningPlan.Operation.Add, ""));
       
            plan.add(adAccountReq);
          } 
          
        }

      }
    }



    Provisioner provisioner = new Provisioner(context);  
    provisioner.setAssigner("IDM Team");  
    try
    {
      provisioner.setNoLocking(true);
      provisioner.setOptimisticProvisioning(true);
    
      provisioner.execute(plan);    

    }
    catch(GeneralException e)
    {
      logger.debug("Exception occurred in compiling plan to modify link ::"+e.getMessage());
    }
    finally
    {

      if(null!=targetIdentity)
      {
        //context.decache(targetIdentity);
      }
    }
    logger.debug("Exiting method updateLink");
  }



  /***************************************************************************************************
	* This method gets the Birthright roles assigned for an identity.
  * Input : idenName - The source Identity name
	* Output : Gets the assigned roles for an Identity
  * Returns : List
	***************************************************************************************************/
  public List getBirthRightAssignedRolesForIdentity(String idenName)
  {
    logger.debug("Entering method getBirthRightAssignedRolesForIdentity");
    Identity roleIdentity = context.getObjectByName(Identity.class,idenName);
    List assignedBirthrightRolesList = new ArrayList();
    Set rolesSet = new HashSet();
    rolesSet.add("BirthrightRole-ServiceNow");
    rolesSet.add("GSuite Access");

    List rolesAssignedList = roleIdentity.getAssignedRoles();
    if(null!=rolesAssignedList)
    {
      ProvisioningPlan plan = new ProvisioningPlan();
      if(roleIdentity!=null)
      {
        plan.setIdentity(roleIdentity);

        for(Bundle assignRole : rolesAssignedList)
        {
          String assignedRoleName = assignRole.getName();
          if(null!=assignRole && null!=assignedRoleName && (rolesSet.contains(assignedRoleName)) || 
             (assignedRoleName.startsWith("BirthrightRole-AD-")))
          {
            assignedBirthrightRolesList.add(assignRole);
          }
        }

        //context.decache(roleIdentity);
      }
    }
    logger.debug("Exiting method getBirthRightAssignedRolesForIdentity");
    return assignedBirthrightRolesList;
  }

  /***************************************************************************************************
	* This method removes the Birthright roles from an identity.
  * Input : idenName - The source Identity name
	* Output : Removes the assigned roles from an Identity
  * Returns : nothing
	***************************************************************************************************/
  public void removeBirthRightRolesFromIdentity(String idenName)
  {
    logger.debug("Entering method removeBirthRightRolesFromIdentity");
    Identity roleIdentity = context.getObjectByName(Identity.class,idenName);

    Set rolesSet = new HashSet();
    rolesSet.add("BirthrightRole-ServiceNow");
    rolesSet.add("GSuite Access");

    List rolesAssignedList = roleIdentity.getAssignedRoles();

    ProvisioningPlan plan = new ProvisioningPlan();
    if(roleIdentity!=null)
    {
      plan.setIdentity(roleIdentity);

      for(Bundle assignRole : rolesAssignedList)
      {
        String assignedRoleName = assignRole.getName();
        if(null!=assignRole && null!=assignedRoleName && (rolesSet.contains(assignedRoleName)) || (assignedRoleName.startsWith("BirthrightRole-AD-")))
        {
          plan.add("IIQ", idenName, "assignedRoles", ProvisioningPlan.Operation.Remove, assignedRoleName);
        }
      }

      Provisioner provisioner = new Provisioner(context);
      provisioner.setNoRoleExpansion(false);
      provisioner.setLocalUpdate(true);
      provisioner.execute(plan);
    }

    //context.decache(roleIdentity);
    logger.debug("Exiting method removeBirthRightRolesFromIdentity");
  }


  /***************************************************************************************************
	* This method adds the Birthright roles to an identity.
  * Input : idenName - The source Identity name
  * Input : List - List of roles to be added.
	* Output : adds the assigned roles to an Identity
  * Returns : nothing
	***************************************************************************************************/
  public void addBirthRightRolesToIdentity(String idenName, List assignedRolesList)
  {
    logger.debug("Entering method addBirthRightRolesToIdentity");
    Identity roleIdentity = context.getObjectByName(Identity.class,idenName);

    List rolesAssignedList = roleIdentity.getAssignedRoles();

    ProvisioningPlan plan = new ProvisioningPlan();
    if(roleIdentity!=null)
    {
      plan.setIdentity(roleIdentity);

      for(Bundle assignRole : assignedRolesList)
      {
        String assignedRoleName = assignRole.getName();
        if(null!=assignedRoleName && !rolesAssignedList.contains(assignRole))
        {
          plan.add("IIQ", idenName, "assignedRoles", ProvisioningPlan.Operation.Add, assignedRoleName);
        }
      }

      Provisioner provisioner = new Provisioner(context);
      provisioner.setNoRoleExpansion(false);
      provisioner.setLocalUpdate(true);
      provisioner.execute(plan);

      //context.decache(roleIdentity);
    }

    logger.debug("Exiting method addBirthRightRolesToIdentity");
  }

  /***************************************************************************************************
    * This method returns the profile type
    * Returns : string - the profile type
    ***************************************************************************************************/
  public String getProfileType(String parentName)
  {
    logger.debug("Entering method getProfileType");
    String profileType = "OtherPersona";
    boolean isEmployeePersona = false;
    boolean isProviderPersona = false;
    Identity parentIdentity = context.getObjectByName(Identity.class,parentName);
    if(null!=parentIdentity)
    {
      List srclinks=parentIdentity.getLinks();

      List employeeProfileList = new ArrayList();
      employeeProfileList.add("DB-Peoplesoft-HCM-Primary");

      List providerProfileList = new ArrayList();
      providerProfileList.add("Midas Seeker - Provider Onboarding");
      providerProfileList.add("MDStaff - Ascension");
      providerProfileList.add("MDStaff - AMITA");
      providerProfileList.add("Morrisey");

      if(null!=scrLinks)
      {
        for(Link link : srclinks)
        {
          if(null!=link && employeeProfileList.contains(link.getApplicationName()))
          {
            isEmployeePersona = true;
            break;
          }
          else if(null!=link && providerProfileList.contains(link.getApplicationName()))
          {
            isProviderPersona = true;
            break;
          }
        }
      }
    }
    if(isEmployeePersona)
    {
      profileType = "EmployeePersona";
    }
    else if(isProviderPersona)
    {
      profileType = "ProviderPersona";
    }
    else
    {
      String type = parentIdentity.getAttribute("type");
      if(null!=type && type.equalsIgnoreCase("non-hr contractor"))
      {
        profileType = "NonHRContractorPersona";
      }
    }
    //context.decache(parentIdentity);
    logger.debug("Exiting method getProfileType");
    return profileType;
  }



  /***************************************************************************************************
    * This method calculates the child persona SID given the parent name
    * Input : parentName - The name of the matching Identity
    * Output : Checks if EmployeeProfile or not
    * Returns : String - the calculated child persona sid
    ***************************************************************************************************/
  public String determineChildSID(String parentName)
  {
    logger.debug("Entering method determineChildSID");
    String childSID = null;
    Identity parentIden = context.getObjectByName(Identity.class,parentName);

    //Get existing parent child personas 
    List childPersonaList = parentIden.getAttribute("childPersonas");
    List integerList = new ArrayList();
    if(null!=childPersonaList)
    {
      for(String chldsid : childPersonaList)
      {
        integerList.add(Integer.parseInt(chldsid));
      }

      Integer maxVal = Collections.max(integerList);
      String selectSid = String.valueOf(maxVal);
      return getChildSidFromInputSid(selectSid);
    }
    else
    {
      //This child is the first child persona for the parent
      String parentSID = parentIden.getAttribute("internalId");
      childSID = getChildSidFromInputSid(parentSID);
    }
    logger.debug("Exiting method determineChildSID");
    return childSID;
  }


  /***************************************************************************************************
    * This method calculates the child persona SID given the input SID value by getting the next value
    * Input : String - inputSid - The input SID
    * Output : Calculates the child persona SID given the input SID value
    * Returns : String - the calculated child persona sid
    ***************************************************************************************************/
  public String getChildSidFromInputSid(String inputSid)
  {
    logger.debug("Entering method getChildSidFromInputSid");
    String resSID = null;
    try
    {
      if(null!=inputSid)
      {
        String lastDigitSID = ""+inputSid.charAt(inputSid.length()-1);
        String parentSID9Digits = inputSid.substring(0,inputSid.length()-1);
        resSID = parentSID9Digits + "" + (Integer.parseInt(lastDigitSID)+1);
      }
    }
    catch(Exception e)
    {
      logger.error("Error occurred. Details:\n"+e.getMessage());
    }
    logger.debug("Exiting method getChildSidFromInputSid");
    return resSID;
  }


  /***************************************************************************************************
    * This method gets the Child Persona Identites from IIQ
    * Input : List - childPersonaList - The list containing child persona SIDs
    * Output : This method gets the Child Persona Identites from IIQ
    * Returns : List - the list of child persona identity names
    ***************************************************************************************************/
  public List getChildIdentities(List childPersonaList)
  { 
    logger.debug("Entering method getChildIdentities");
    List linkedIdentities = new ArrayList();
    Iterator identityIterator = null;
    if(null!=childPersonaList)
    {
      for(String gid: childPersonaList)
      {
        if(gid!=null)
        {
          QueryOptions queryOptions = new QueryOptions();
          queryOptions.addFilter(Filter.and(Filter.eq("internalId", gid)));
          identityIterator = context.search(Identity.class, queryOptions);
          if(null!=identityIterator && identityIterator.hasNext())
          {
            Identity retrievedIdentity = (Identity)identityIterator.next();
            if(null!=retrievedIdentity)
            {
              String personaType = retrievedIdentity.getAttribute("personaType");
              if(null!=personaType && personaType.equalsIgnoreCase("Child"))
              {
                linkedIdentities.add(retrievedIdentity.getName());
              }
            }
          }
        }
      }
    }

    if(null!=identityIterator)
    {
      Util.flushIterator(identityIterator);
    }
    logger.debug("Exiting method getChildIdentities");
    return linkedIdentities;
  }


  /***************************************************************************************************
	* This method searches for a exact match identity in the IIQ
  * Exact Match Criteria : 
  * Criteria : Matching firstname, lastname, last 4 ssn, dob
	* Method returns the names of the partial matching identities
	* Output : Finds matching identities
  * Returns : String - username of exact matching identity
	***************************************************************************************************/
  public String exactMatchSearch(String identityName)
  {
    logger.debug("Entering method exactMatchSearch");
    String cubeName = null;
    Identity currentIdentity = context.getObjectByName(Identity.class,identityName);
    String currentIdentityId = currentIdentity.getId();

    String firstName = currentIdentity.getAttribute("firstname");
    String lastName = currentIdentity.getAttribute("lastname");
    String ssn4 = getDecryptAESValue(currentIdentity.getAttribute("ssn"));
    String dob = getDecryptAESValue(currentIdentity.getAttribute("dob"));
    String encryptSSN = encryptAES(ssn4);
    String encryptDOB = encryptAES(dob);

    QueryOptions queryOptions = new QueryOptions();
    Filter Filter0 = Filter.and(Filter.eq("firstname", firstName),Filter.eq("lastname", lastName), Filter.eq("ssn", ssn4), Filter.eq("dob", dob));
    Filter Filter1 = Filter.and(Filter.eq("firstname", firstName),Filter.eq("lastname", lastName), Filter.eq("ssn", encryptSSN), Filter.eq("dob", encryptDOB));

    List filters = new ArrayList ();
    filters.add(Filter0);
    filters.add(Filter1);

    Filter finalFilter = Filter.or(filters);
    queryOptions.addFilter(finalFilter);

    Iterator identityIterator = context.search(Identity.class, queryOptions);
    if(null!=identityIterator)
    {
      while(identityIterator.hasNext())
      {
        Identity retrievedIdentity = (Identity)identityIterator.next();
        String retrievedIdentityId = retrievedIdentity.getId();
        if(!retrievedIdentityId.equalsIgnoreCase(currentIdentityId))
        {
          String personaType = retrievedIdentity.getAttribute("personaType");
          if(null!=personaType && personaType.equalsIgnoreCase("Primary"))
          {
            cubeName = retrievedIdentity.getName();
            //context.decache(retrievedIdentity);
            break;
          }
        }
      }
      //context.decache(currentIdentity);
      Util.flushIterator(identityIterator);
    }
    logger.debug("Exiting method exactMatchSearch");
    return cubeName;
  }


  /***************************************************************************************************
	* This method searches for a partial match identity in the IIQ
  * Partial Match Criteria : 
  * Criteria 1: Matching lastname, ssn, dob
  * Criteria 2: Matching firstname, ssn, dob
  * Criteria 3: Matching firstname, lastname, dob
  * Criteria 4: Matching firstname, lastname, ssn
	* Method returns the names of the partial matching identities
	* Output : Finds matching identities
  * Returns : Set - usernames - identities - string.
	***************************************************************************************************/
  public Set partialMatchSearch(String identityName)
  {
    logger.debug("Entering method partialMatchSearch");
    Set cubeNames = new HashSet();
    String cubeName = null;
    Identity currentIdentity = context.getObjectByName(Identity.class,identityName);
    String currentIdentityId = currentIdentity.getId();

    String firstName = currentIdentity.getAttribute("firstname");
    String lastName = currentIdentity.getAttribute("lastname");
    String ssn4 = getDecryptAESValue(currentIdentity.getAttribute("ssn"));
    String dob = getDecryptAESValue(currentIdentity.getAttribute("dob"));
    String encryptSSN = encryptAES(ssn4);
    String encryptDOB = encryptAES(dob);

    QueryOptions queryOptions = new QueryOptions();
    Filter Filter1 = Filter.and(Filter.eq("lastname", lastName), Filter.eq("ssn", ssn4), Filter.eq("dob", dob));
    Filter Filter2 = Filter.and(Filter.eq("firstname", firstName), Filter.eq("ssn", ssn4), Filter.eq("dob", dob));
    Filter Filter3 = Filter.and(Filter.eq("firstname", firstName), Filter.eq("lastname", lastName), Filter.eq("dob", dob));
    Filter Filter4 = Filter.and(Filter.eq("firstname", firstName), Filter.eq("lastname", lastName), Filter.eq("ssn", ssn4));
    Filter Filter5 = Filter.and(Filter.eq("lastname", lastName), Filter.eq("ssn", encryptSSN), Filter.eq("dob", encryptDOB));
    Filter Filter6 = Filter.and(Filter.eq("firstname", firstName), Filter.eq("ssn", encryptSSN), Filter.eq("dob", encryptDOB));
    Filter Filter7 = Filter.and(Filter.eq("firstname", firstName), Filter.eq("lastname", lastName), Filter.eq("dob", encryptDOB));
    Filter Filter8 = Filter.and(Filter.eq("firstname", firstName), Filter.eq("lastname", lastName), Filter.eq("ssn", encryptSSN));
    //Filter Filter9 = Filter.and(Filter.eq("firstname", firstName), Filter.eq("lastname", lastName));

    List filters = new ArrayList ();
    filters.add(Filter1);
    filters.add(Filter2);
    filters.add(Filter3);
    filters.add(Filter4);
    filters.add(Filter5);
    filters.add(Filter6);
    filters.add(Filter7);
    filters.add(Filter8);
    //filters.add(Filter9);

    Filter finalFilter = Filter.or(filters);
    queryOptions.addFilter(finalFilter);

    Iterator identityIterator = context.search(Identity.class, queryOptions);
    while(identityIterator.hasNext())
    {
      Identity retrievedIdentity = (Identity)identityIterator.next();
      String retrievedIdentityId = retrievedIdentity.getId();
      if(!retrievedIdentityId.equalsIgnoreCase(currentIdentityId))
      {
        cubeName = retrievedIdentity.getName();
        if(!cubeNames.contains(cubeName))
        {
          cubeNames.add(cubeName);
        }
      }
      //context.decache(retrievedIdentity);
    }
    //context.decache(currentIdentity);
    Util.flushIterator(identityIterator);
    logger.debug("Exiting method partialMatchSearch");
    return cubeNames;
  }

