  /***************************************************************************************************
	* This method is a utility method to trigger a workflow
  * idName - the identity name
  * workflowName - the workflow name
  * trigger - the identity trigger
	* Method launches the workflow name.
	* Output : boolean - active or not.
	***************************************************************************************************/
  public void triggerWorkflow(String idName, String workflowName, IdentityTrigger trigger)
  {
    logger.debug("Entering method triggerWorkflow");

    try
    {
      WorkflowLaunch wfl = new WorkflowLaunch();
      wfl.setWorkflowRef(workflowName);
      wfl.setLauncher(context.getUserName()); 

      String requestName = trigger.getName() + " FOR " + idName + "  ["+identityName+"]  ";

      wfl.setCaseName(requestName);

      Map wfArgsMap =  new HashMap();
      wfArgsMap.put("identityName", idName);

      wfl.setVariables(wfArgsMap);
      Workflower wf = new Workflower(context);
      try 
      {
        wf.launch(wfl);
      } 
      catch (GeneralException e) 
      {
        logger.error("Exception   " + e.getMessage());
      }
    }
    catch(Exception e)
    {
      logger.error(e.getMessage());
    }
    logger.debug("Exiting method triggerWorkflow");
  }

 public void triggerWorkflow(String idName, String workflowName, IdentityTrigger trigger, String flow)
  {
    logger.debug("Entering method triggerWorkflow");

    try
    {
      WorkflowLaunch wfl = new WorkflowLaunch();
      wfl.setWorkflowRef(workflowName);
      wfl.setLauncher(context.getUserName()); 

      String requestName = trigger.getName() + " FOR " + idName + "  ["+identityName+"]  ";

