  /***************************************************************************************************
	* This method finds if the identity is an MDStaff-Ascension user with No NPI
	* Method returns true/false for the identity 
	* Output : boolean - true / false
	***************************************************************************************************/
  public boolean isUserMDStaffAscensionUserWithNoNPI(String identityName)
  {
    logger.debug("Entering method isUserMDStaffAscensionUserWithNoNPI");
    boolean isMDStaffNoNPIUser = false;
    Identity matchIdentity = context.getObjectByName(Identity.class, identityName);
    if(null!=matchIdentity)
    {
      String type = matchIdentity.getAttribute("identityType");
      if(null!=type && type.equalsIgnoreCase("ProviderPersona"))
      {
        List srclinks=matchIdentity.getLinks();
        if(null!=scrLinks)
        {
          for(Link link : srclinks)
          {
            if(null!=link && "MDStaff - Ascension".equalsIgnoreCase(link.getApplicationName()))
            {
              String npiNumber = link.getAttribute("NPI");
              if(null==npiNumber)
              {
                isMDStaffNoNPIUser = true;
              }
            }
          }
        }
      }
      //context.decache(matchIdentity);
    }
    logger.debug("Exiting method isUserMDStaffAscensionUserWithNoNPI");
    return isMDStaffNoNPIUser;
  }


  /***************************************************************************************************
	* This method checks if username needs to be changed based on specific conditions
  * Input : Identity Name
	* Method returns true/false
	* Output : boolean - true / false
	***************************************************************************************************/
  public boolean checkIfUserNameNeedsToBeChanged(String identityName)
  {
    logger.debug("Entering method checkIfUserNameNeedsToBeChanged");
    boolean userNameChangeNeeded = false;

    boolean isAmitaUser = isUserAmitaUserType(identityName);

    boolean isPeopleSoftUser = isPeopleSoftUser(identityName);

    if(isPeopleSoftUser && isAmitaUser){
      isAmitaUser = false;
    }   

    boolean isNonHRContractorUser = isUserNonHRContractorUserType(identityName);

    boolean isUserMDStaffAscensionUserNoNPI = isUserMDStaffAscensionUserWithNoNPI(identityName);

    userNameChangeNeeded = isAmitaUser || isNonHRContractorUser || isUserMDStaffAscensionUserNoNPI;

    logger.debug("Exiting method checkIfUserNameNeedsToBeChanged");
    return userNameChangeNeeded;
  }

  /***************************************************************************************************
	* This method deletes the AD, ServiceNow and GSuite links from source identity if present
  * Input : source - The source Identity name
	* Output : Deletes the AD, ServiceNow and GSuite links from Source to Target identity
  * Returns : nothing
	***************************************************************************************************/
  public void deleteIdentityLinks(String source)
  {
    logger.debug("Entering method deleteIdentityLinks");
    try
    {
      Identity sourceIdentity = context.getObjectByName(Identity.class,source);
      List srclinks=sourceIdentity.getLinks();
      ProvisioningPlan plan = new ProvisioningPlan();
      plan.setIdentity(sourceIdentity);
      plan.setNativeIdentity(source);
      ProvisioningPlan.AccountRequest accReq = new ProvisioningPlan.AccountRequest();
      List accReqs = new ArrayList();

      List appTypeList = new ArrayList();
      appTypeList.add("Active Directory - Direct");
      appTypeList.add("G Suite");
      appTypeList.add("ServiceNow");   

      for(Link linkToBeDeleted : srclinks)
      {
        if(null!=linkToBeDeleted && appTypeList.contains(linkToBeDeleted.getApplication().getType()))
        {
          accReq = new ProvisioningPlan.AccountRequest();
          accReq.setOperation(AccountRequest.Operation.Delete);
          accReq.setApplication(linkToBeDeleted.getApplicationName());
          accReq.setNativeIdentity(linkToBeDeleted.getNativeIdentity());
          plan.add(accReq);
        }
      }
      Provisioner provisioner = new Provisioner(context);
      provisioner.setNoLocking(true);
      provisioner.setOptimisticProvisioning(true);
      provisioner.execute(plan);
    }
    catch(Excpetion e)
    {
      logger.error(e);
    }
    logger.debug("Exiting method deleteIdentityLinks");
  }

  /***************************************************************************************************
	* This method writes audit logs to IIQ in case of various Persona scenarios and use cases
  * Input : action - The audit action
  * Input : auditString1 - Details of the audit
  * Input : auditString2 - Details of the audit
  * Input : identityName - The audit Identity name
	* Output : Writes audit entries for auditing purposes
  * Returns : nothing
	***************************************************************************************************/
  public void writeAuditRecordToIIQ(String action,String auditString1, String auditString2,String auditString3, String identityName, String contextName)
  {
    logger.debug("Entering method writeAuditRecord");
    Identity auditIdentity = context.getObjectByName(Identity.class, identityName);
    if (null!=action && Auditor.isEnabled(action) && null!=auditIdentity) 
    {
      AuditEvent event = new AuditEvent();
      event.setAction(action);
      event.setTarget(identityName);

      event.setAttributeName("Process Name");
      if(action.equalsIgnoreCase("PersonaJoiner")) 
      {
        event.setAttributeValue("Persona Joiner Process");
      }
      else if(action.equalsIgnoreCase("PersonaLeaver")) 
      {
        event.setAttributeValue("Persona Leaver Process");
      }
      else if(action.equalsIgnoreCase("PersonaRehire")) 
      {
        event.setAttributeValue("Persona Rehire Process");
      }
      else if(action.equalsIgnoreCase("PersonaRemediation")) 
      {
        event.setAttributeValue("Persona Remediation Process");
      }
      else if(action.equalsIgnoreCase("PersonaUsernameChange")) 
      {
        event.setAttributeValue("Persona Username Change Process : "+contextName);
      }
      else if(action.equalsIgnoreCase("PersonaUsernameMove")) 
      {
        event.setAttributeValue("Persona Username Move Process : "+contextName);
      }
	  else if(action.equalsIgnoreCase("UpdateInternalID")) 
      {
        event.setAttributeValue("Update InternalID Process");
      }

      event.setString1(auditString1);
      event.setString2(auditString2);
      event.setString3(auditString3);

      Auditor.log(event);
      context.commitTransaction();
      logger.debug("Exiting method writeAuditRecord");
    }
  }


  /***************************************************************************************************
	* This method deletes the AD, ServiceNow and GSuite links from source identity
  * Input : source - The source Identity name
	* Ouput : Deletes the AD, ServiceNow and GSuite links from Source identity
  * Returns : nothing
	***************************************************************************************************/
  public void deleteIdentityLinksFromIIQ(InternalContext internalContext, String identityName)
  {
    logger.debug("Entering method deleteIdentityLinksFromIIQ");
    SailPointContext ctx = internalContext.getContext();
    if(null!=ctx)
    {
      try
      {
        Identity sourceIdentity = context.getObjectByName(Identity.class,identityName);
        List srclinks=sourceIdentity.getLinks();
        ProvisioningPlan plan = new ProvisioningPlan();
        plan.setIdentity(sourceIdentity);
        plan.setNativeIdentity(identityName);
        ProvisioningPlan.AccountRequest accReq = new ProvisioningPlan.AccountRequest();
        List accReqs = new ArrayList();

        List appTypeList = new ArrayList();
        appTypeList.add("Active Directory - Direct");
        appTypeList.add("G Suite");
        appTypeList.add("ServiceNow");   

        for(Link linkToBeDeleted : srclinks)
        {
          if(null!=linkToBeDeleted && appTypeList.contains(linkToBeDeleted.getApplication().getType()))
          {
            accReq = new ProvisioningPlan.AccountRequest();
            accReq.setOperation(AccountRequest.Operation.Delete);
            accReq.setApplication(linkToBeDeleted.getApplicationName());
            accReq.setNativeIdentity(linkToBeDeleted.getNativeIdentity());
            plan.add(accReq);
          }
        }
        Provisioner provisioner = new Provisioner(ctx);
        provisioner.setNoLocking(true);
        provisioner.setOptimisticProvisioning(true);
        provisioner.execute(plan);
      }
      catch(Excpetion e)
      {
        logger.error(e);
      }
      finally
      {
        //Release 'context'
        sailpoint.api.SailPointFactory.releasePrivateContext(ctx); 
      }
    }
    logger.debug("Exiting method deleteIdentityLinksFromIIQ");
  }


