  /***************************************************************************************************
  * This method generate new identity name and set to identity name 
  * if the user name already exists in IIQ the code throw exception and generate new user name.
  * Input : source - The source Identity name
	* Return : newly generated name
	***************************************************************************************************/
  synchronized public String setIdentityUserName(String identityName){
    logger.debug("setIdentityUserName Start");

    String newUserName = "";
    if(Util.isNotNullOrEmpty(identityName)){
      Identity tempIdn = ObjectUtil.lockIdentity(context, identityName);
      if(tempIdn != null){
        for(int i = 0;i<3;i++){
          try{
            newUserName = generateUserName(tempIdn.getFirstname(), tempIdn.getLastname());
            tempIdn.setName(newUserName);
            tempIdn.setAttribute("initialName",identityName);
            context.saveObject(tempIdn);
            ObjectUtil.unlockIdentity(context, tempIdn);
            context.commitTransaction();
            identityName = newUserName;           
            break;
          }catch(GeneralException ge){
            logger.error("setIdentityUserName :: Identity name already exists generating new one - "+ge.getMessage());           
          }finally{
            logger.debug("setIdentityUserName end");
          }
        }
      }
    }
    logger.debug("setIdentityUserName end");
    return identityName;
  }

  /**
	 * Set eventsequence value based on the event triggered
	 * @param identityName
   * @param eventName
	 */
  public void setTriggeredEventSequence(String identityName, String eventName){
    if(Util.isNotNullOrEmpty(identityName) && Util.isNotNullOrEmpty(eventName)){
      Identity identity = null;
      String customObjName = "Ascension-custom-generalConfiguration";
      Custom customObj = null;
      String eventDisplayName = "";
      try{   
        customObj = ObjectUtil.transactionLock(context, Custom.class, customObjName);        
        identity = ObjectUtil.transactionLock(context, Identity.class, identityName);
        if(null != customObj && !Util.isEmpty(customObj.get("EventNameMapping"))){
          eventDisplayName = customObj.get("EventNameMapping").get(eventName);
        }
        if(null != identity &&  Util.isNotNullOrEmpty(eventDisplayName)){
          ArrayList existingSeq = identity.getAttribute("eventSequence");
          if(!Util.isEmpty(existingSeq))
          {
            existingSeq.add(eventDisplayName);
            identity.setAttribute("eventSequence", existingSeq);   
          }       
          else
          {
            ArrayList newSeq = new ArrayList();
            newSeq.add(eventDisplayName);
            identity.setAttribute("eventSequence", newSeq);   
          }            
        }
      }
      catch (GeneralException ge) 
      {
        logger.error(ge.getMessage());
      }
      finally 
      {
        if (identity != null) 
        {
          if (identity.getLock() != null) 
          {
            identity.setLock(null);
          }

          context.startTransaction();
          context.saveObject(identity);
          context.commitTransaction();
          //context.decache(identity);
        }
      }
    }
  }

  /**
	 * GET eventsequence value based on the event triggered
	 * @param identityName
	 * @return String recent EVENTNAME
	 */
  public String getTriggeredEventSequence(String identityName){
    String value = "";
    if(Util.isNotNullOrEmpty(identityName)){
      Identity identity = context.getObjectByName(Identity.class, identityName);
      if(null != identity){
        ArrayList existingSeq = identity.getAttribute("eventSequence");
        if(!Util.isEmpty(existingSeq)){
          value = existingSeq.get(existingSeq.size() - 1);
        }
      }
    }
    return value;
  }
  
  /**
	 * Check uniqueness of the internalid
	 * @param internalid the internalid
	 * @return Unique internal id 
	 */
  public String checkDuplicateGenerateNewInternalID(String internalID) {
    String methodName = "checkDuplicateInternalID";
    logger.debug("Entering"+methodName);

    if(Util.isNullOrEmpty(internalID) || !isNumericValue(internalID) ){
      internalID = generateNextSailpointInternalIdentifier();
    }

    Filter filter = Filter.ignoreCase(Filter.eq("internalId", internalID));

    QueryOptions qo = new QueryOptions();
    qo.add(filter);
    int count = context.countObjects(Identity.class,qo);

    if(count > 0)
    {
      internalID = generateNextSailpointInternalIdentifier();
      internalID = checkDuplicateGenerateNewInternalID(internalID);
    }

    logger.debug("Exiting"+methodName);
    return internalID;
  }
  
  
  /**
	 * check input value is number or not
	 * @param value
	 * @return true if value is integer value
	 */
	public boolean isNumericValue(String value) throws Exception{
		log.info("isNumericValue Starting");
		try { 
			Integer.parseInt(value); 
			return true;
		} catch (NumberFormatException e) { 
			return false;
		} 
	}
	
