    String setid_location = (String) link.getAttribute("SETID_LOCATION");
    String per_org = (String) link.getAttribute("PER_ORG");
    String result="";
    String setIdLocationCwr="ILARL";
    try{
      if(Util.isNotNullOrEmpty(per_org) && Util.isNotNullOrEmpty(setid_location)) {
        if(per_org.equalsIgnoreCase("CWR") && setid_location.equalsIgnoreCase(setIdLocationCwr)){
          result  = "ContractorPersona";		      
        }
        else
        {
          result  = "EmployeePersona";  
        }
        return result;
        debug(logName,"identityType is :" + result);   
      }
    }catch(Exception e){
      error(logName, "Exception: " + e.getMessage());
